namespace sv_f6b233d59b6a4db2960541c94cbb0f1d.Services;

public sealed class WarehouseStateService
{
    public static IReadOnlyList<(string Id, string Name)> AvailableWarehouses { get; } =
    [
        ("WH-001", "Warehouse A — Main Distribution"),
        ("WH-002", "Warehouse B — East Regional"),
        ("WH-003", "Warehouse C — West Regional"),
        ("WH-004", "Warehouse D — Cold Storage"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    /// <summary>
    /// Raised on the calling thread — subscribers must marshal to their own
    /// synchronization context (e.g. InvokeAsync) before touching UI state.
    /// </summary>
    public event Func<Task>? OnWarehouseChanged;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (warehouseId == _currentWarehouseId)
            return;

        if (AvailableWarehouses.All(w => w.Id != warehouseId))
            throw new ArgumentException($"Unknown warehouse: {warehouseId}");

        _currentWarehouseId = warehouseId;

        if (OnWarehouseChanged is not null)
            await OnWarehouseChanged.Invoke();
    }
}

namespace sv_f6b233d59b6a4db2960541c94cbb0f1d.Services;

public sealed class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int LatestLowStockCount { get; private set; }

    /// <summary>
    /// Raised whenever new alert data arrives. Subscribers must marshal to
    /// their own synchronization context before updating UI.
    /// </summary>
    public event Func<Task>? OnAlertCountChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnWarehouseChanged += HandleWarehouseChangedAsync;
    }

    /// <summary>Simulates a database query — returns a random 0–15 value.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(Random.Shared.Next(0, 16));
    }

    /// <summary>
    /// Reference-counted start: the first subscriber starts the timer;
    /// subsequent calls just bump the count.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
            StartTimer();
    }

    /// <summary>
    /// Reference-counted stop: the last subscriber stops the timer.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
            StopTimer();
    }

    private void StartTimer()
    {
        StopTimer();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopTimer()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Immediately fetch once on start.
        await FetchAndNotifyAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer!.WaitForNextTickAsync(ct))
                    break;

                await FetchAndNotifyAsync();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task FetchAndNotifyAsync()
    {
        LatestLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);

        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }

    private async Task HandleWarehouseChangedAsync()
    {
        // When the warehouse changes, immediately refresh alert data
        // so every subscriber sees up-to-date counts for the new site.
        if (_subscriberCount > 0)
            await FetchAndNotifyAsync();
    }

    public void Dispose()
    {
        _warehouseState.OnWarehouseChanged -= HandleWarehouseChangedAsync;
        StopTimer();
    }
}

