@using sv_f6b233d59b6a4db2960541c94cbb0f1d.Services
@inject WarehouseStateService WarehouseState
@implements IDisposable

<select class="form-select form-select-sm"
        style="width: 280px;"
        value="@WarehouseState.CurrentWarehouseId"
        @onchange="OnSelectionChanged">
    @foreach (var wh in WarehouseStateService.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnWarehouseChanged += HandleWarehouseChangedAsync;
    }

    private async Task OnSelectionChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
            await WarehouseState.SetWarehouseAsync(id);
    }

    private async Task HandleWarehouseChangedAsync()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnWarehouseChanged -= HandleWarehouseChangedAsync;
    }
}

