@page "/dashboard"
@rendermode InteractiveServer

@using sv_f6b233d59b6a4db2960541c94cbb0f1d.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text text-muted">ID: @WarehouseState.CurrentWarehouseId</p>
    </div>
</div>

<div class="card mb-4" style="max-width: 500px;">
    <div class="card-body d-flex align-items-center justify-content-between">
        <div>
            <h5 class="card-title mb-0">Low-Stock Alerts</h5>
            <small class="text-muted">Refreshes every 10 seconds</small>
        </div>

        @if (AlertService.LatestLowStockCount > 0)
        {
            <span class="badge bg-danger fs-5">@AlertService.LatestLowStockCount</span>
        }
        else
        {
            <span class="badge bg-success fs-5">0</span>
        }
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnWarehouseChanged += HandleStateChangedAsync;
        AlertService.OnAlertCountChanged += HandleStateChangedAsync;

        // Start polling when the dashboard becomes visible.
        AlertService.StartPolling();
    }

    private async Task HandleStateChangedAsync()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        // Stop polling when the user leaves the page.
        AlertService.StopPolling();

        WarehouseState.OnWarehouseChanged -= HandleStateChangedAsync;
        AlertService.OnAlertCountChanged -= HandleStateChangedAsync;
    }
}

